# Главный модуль приложения, который инициализирует все компоненты, управляет жизненным циклом приложения и обеспечивает 
# взаимодействие между различными частями системы. он отвечает за загрузку конфигурации, установку соединения с базой данных, 
# управление ключами и аутентификацией, а также за запуск графического интерфейса пользователя. этот модуль служит точкой входа 
# в приложение и координирует работу всех остальных компонентов для обеспечения безопасного и удобного управления криптографическими данными.
# при первом запуске приложения он проверяет наличие базы данных и, если она отсутствует, запускает мастер настройки для создания новой базы данных и установки пароля.

import sys
from pathlib import Path
from PyQt6.QtWidgets import QApplication, QDialog
from core.config import ConfigManager
from database.db import DatabasePool
from core.crypto.key_storage import KeyStorage
from core.key_manager import KeyManager
from core.crypto.authentication import Authenticator
from core.state_manager import StateManager
from core.events import EventBus
from core.vault.entry_manager import EntryManager
from gui.main_window import MainWindow
from gui.setup_wizard import SetupWizard
from gui.login_dialog import LoginDialog
from core.clipboard.platform_adapter import get_platform_clipboard_adapter
from core.clipboard.clipboard_service import ClipboardService
from core.clipboard.clipboard_monitor import ClipboardMonitor


def main(): # функция main, которая служит точкой входа в приложение. 
    app = QApplication(sys.argv)# инициализируем приложение PyQt6
    config = ConfigManager()# инициализируем менеджер конфигурации для загрузки настроек приложения
    db_path = config.get_database_path()# получаем путь к базе данных из конфигурации и проверяем его наличие. если база данных не существует, запускаем мастер настройки для создания новой базы данных и установки пароля. если база данных существует, запускаем диалог входа для аутентификации пользователя перед доступом к данным.

    if not db_path or not Path(db_path).exists():# если база данных не существует, запускаем мастер настройки для создания новой базы данных и установки пароля. если база данных существует, запускаем диалог входа для аутентификации пользователя перед доступом к данным.
        wizard = SetupWizard()# запускаем мастер настройки для создания новой базы данных и установки пароля. если пользователь отменяет мастер, приложение завершается. если пользователь успешно завершает мастер, сохраняем путь к базе данных в конфигурации, инициализируем базу данных, менеджер ключей и менеджер состояния, и публикуем событие входа пользователя.
        if wizard.exec() != QDialog.DialogCode.Accepted:# если пользователь отменяет мастер, приложение завершается. если пользователь успешно завершает мастер, сохраняем путь к базе данных в конфигурации, инициализируем базу данных, менеджер ключей и менеджер состояния, и публикуем событие входа пользователя.
            sys.exit(0)# если пользователь отменяет мастер, приложение завершается. если пользователь успешно завершает мастер, сохраняем путь к базе данных в конфигурации, инициализируем базу данных, менеджер ключей и менеджер состояния, и публикуем событие входа пользователя.
        db_path = wizard.db_path# сохраняем путь к базе данных в конфигурации, инициализируем базу данных, менеджер ключей и менеджер состояния, и публикуем событие входа пользователя.
        config.set_database_path(db_path)# сохраняем путь к базе данных в конфигурации, инициализируем базу данных, менеджер ключей и менеджер состояния, и публикуем событие входа пользователя.
        pool = DatabasePool(db_path)# инициализируем базу данных, менеджер ключей и менеджер состояния, и публикуем событие входа пользователя.
        pool.migrate()# выполняем миграцию базы данных для создания необходимых таблиц и схем при первом запуске приложения
        key_storage = KeyStorage(pool)# инициализируем хранилище ключей для управления сохранением и загрузкой параметров аутентификации и PBKDF2 в базе данных
        key_manager = KeyManager(key_storage, config={# инициализируем менеджер ключей для управления ключами шифрования, включая инициализацию, разблокировку, доступ к ключу, блокировку и смену пароля. он использует KeyStorage для сохранения и загрузки параметров аутентификации и PBKDF2, KeyDerivation для генерации ключей на основе пароля и соли, KeyCache для хранения активного ключа в памяти, и публикует события входа и выхода пользователя через шину событий.
            "argon2_time": 3,
            "argon2_memory": 65536,
            "argon2_parallelism": 4,
            "pbkdf2_iterations": 100000,
        })
        password = wizard.password_entry.text()# получаем мастер-пароль, введенный пользователем в мастере настройки, и используем его для инициализации менеджера ключей и разблокировки доступа к данным. этот пароль будет использоваться для генерации ключа шифрования, который будет храниться в кэше менеджера ключей для доступа к зашифрованным данным.
        key_manager.initialize(password)# инициализируем менеджер ключей с новым паролем. он генерирует соль, создает хэш аутентификации и сохраняет их в хранилище. этот метод должен быть вызван при первом запуске приложения или при сбросе конфигурации.
        key_manager.unlock(password)# разблокируем менеджер ключей с помощью пароля. он проверяет пароль и, если он верный, генерирует ключ шифрования и сохраняет его в кэше. этот метод должен быть вызван перед доступом к зашифрованным данным.

        state_manager = StateManager(config)# инициализируем менеджер состояния для управления состоянием приложения, таким как блокировка и разблокировка, и публикация событий состояния через шину событий
        event_bus = EventBus()# инициализируем шину событий для управления событиями в приложении, такими как вход и выход пользователя, изменения данных и другие действия. шина событий позволяет различным компонентам приложения взаимодействовать друг с другом через публикацию и подписку на события, обеспечивая слабую связанность и гибкость в архитектуре приложения.
        authenticator = Authenticator(key_manager, event_bus, state_manager)# инициализируем аутентификатор для управления процессом входа и выхода пользователя, а также для обработки неудачных попыток входа с задержкой для предотвращения атак перебором паролей. аутентификатор использует менеджер ключей для проверки пароля и управления доступом к данным, шину событий для публикации событий входа и выхода, и менеджер состояния для блокировки и разблокировки приложения.
        authenticator.failed_attempts = 0# сбрасываем счетчик неудачных попыток входа при успешной аутентификации
        state_manager.unlock()# разблокируем состояние приложения после успешной аутентификации
        event_bus.publish("UserLoggedIn")# публикуем событие "UserLoggedIn" после успешной аутентификации для уведомления других компонентов приложения о том, что пользователь вошел в систему и доступ к данным разблокирован.
    else:
        pool = DatabasePool(db_path)# инициализируем базу данных, менеджер ключей и менеджер состояния, и публикуем событие входа пользователя. если база данных существует, запускаем диалог входа для аутентификации пользователя перед доступом к данным.
        pool.migrate()# выполняем миграцию базы данных для создания необходимых таблиц и схем при первом запуске приложения
        key_storage = KeyStorage(pool)# инициализируем хранилище ключей для управления сохранением и загрузкой параметров аутентификации и PBKDF2 в базе данных
        key_manager = KeyManager(key_storage, config={# инициализируем менеджер ключей для управления ключами шифрования, включая инициализацию, разблокировку, доступ к ключу, блокировку и смену пароля. он использует KeyStorage для сохранения и загрузки параметров аутентификации и PBKDF2, KeyDerivation для генерации ключей на основе пароля и соли, KeyCache для хранения активного ключа в памяти, и публикует события входа и выхода пользователя через шину событий.
            "argon2_time": 3,
            "argon2_memory": 65536,
            "argon2_parallelism": 4,
            "pbkdf2_iterations": 100000,
        })
        state_manager = StateManager(config)# инициализируем менеджер состояния для управления состоянием приложения, таким как блокировка и разблокировка, и публикация событий состояния через шину событий
        event_bus = EventBus()# инициализируем шину событий для управления событиями в приложении, такими как вход и выход пользователя, изменения данных и другие действия. шина событий позволяет различным компонентам приложения взаимодействовать друг с другом через публикацию и подписку на события, обеспечивая слабую связанность и гибкость в архитектуре приложения.
        authenticator = Authenticator(key_manager, event_bus, state_manager)# инициализируем аутентификатор для управления процессом входа и выхода пользователя, а также для обработки неудачных попыток входа с задержкой для предотвращения атак перебором паролей. аутентификатор использует менеджер ключей для проверки пароля и управления доступом к данным, шину событий для публикации событий входа и выхода, и менеджер состояния для блокировки и разблокировки приложения.
        login_dialog = LoginDialog(authenticator)# запускаем диалог входа для аутентификации пользователя перед доступом к данным. если пользователь отменяет диалог, приложение завершается. если пользователь успешно проходит аутентификацию, менеджер ключей разблокируется, состояние приложения разблокируется, и публикуется событие "UserLoggedIn" для уведомления других компонентов приложения о том, что пользователь вошел в систему и доступ к данным разблокирован.
        if login_dialog.exec() != QDialog.DialogCode.Accepted:# если пользователь отменяет диалог, приложение завершается. если пользователь успешно проходит аутентификацию, менеджер ключей разблокируется, состояние приложения разблокируется, и публи
            sys.exit(0)# если пользователь отменяет диалог, приложение завершается. если пользователь успешно проходит аутентификацию, менеджер ключей разблокируется, состояние приложения разблокируется, и публи

    entry_manager = EntryManager(pool, key_manager)# инициализируем менеджер записей для управления CRUD операциями над записями в базе данных. он использует пул соединений с базой данных для выполнения запросов и менеджер ключей для доступа к ключу шифрования при сохранении и загрузке зашифрованных данных. менеджер записей обеспечивает абстрактный интерфейс для взаимодействия с данными, связанными с безопасностью и конфиденциальностью, и поддерживает шифрование для чувствительных данных.

    clipboard_adapter = get_platform_clipboard_adapter()# инициализируем адаптер буфера обмена для взаимодействия с системным буфером обмена. этот адаптер обеспечивает абстрактный интерфейс для копирования и вставки данных в буфер обмена, позволяя приложению работать с буфером обмена на разных платформах без необходимости учитывать специфические детали реализации каждой платформы.

    clipboard_service = ClipboardService(# инициализируем сервис буфера обмена для управления взаимодействием с буфером обмена, включая копирование данных в буфер обмена, мониторинг изменений в буфере обмена и публикацию событий при изменении буфера обмена. он использует адаптер буфера обмена для взаимодействия с системным буфером обмена, шину событий для публикации событий изменения буфера обмена, и менеджер состояния для проверки состояния приложения перед выполнением операций с буфером обмена.
        platform_adapter=clipboard_adapter,
        event_system=event_bus,
        config=config,
        state_manager=state_manager,
    )
    
    monitor = ClipboardMonitor(clipboard_service, clipboard_adapter)# инициализируем монитор буфера обмена для отслеживания изменений в буфере обмена и уведомления сервиса буфера обмена о любых изменениях. он использует сервис буфера обмена для управления взаимодействием с буфером обмена и адаптер буфера обмена для взаимодействия с системным буфером обмена. монитор запускается при запуске приложения и продолжает работать в фоновом режиме, обеспечивая своевременное обнаружение изменений в буфере обмена и публикацию событий при изменении буфера обмена.
    clipboard_service.set_monitor(monitor)# устанавливаем монитор буфера обмена в сервис буфера обмена для обеспечения взаимодействия между ними и своевременного обнаружения изменений в буфере обмена.
    monitor.start()# запускаем монитор буфера обмена для отслеживания изменений в буфере обмена и уведомления сервиса буфера обмена о любых изменениях. он использует сервис буфера обмена для управления взаимодействием с буфером обмена и адаптер буфера обмена для взаимодействия с системным буфером обмена. монитор продолжает работать в фоновом режиме, обеспечивая своевременное обнаружение изменений в буфере обмена и публикацию событий при изменении буфера обмена.

    window = MainWindow(# инициализируем главное окно приложения, передавая ему все необходимые компоненты для управления данными, аутентификацией, состоянием приложения и взаимодействием с буфером обмена. главное окно служит основным интерфейсом пользователя для взаимодействия с приложением, отображая данные, предоставляя доступ к функциям управления записями, и обеспечивая удобный способ управления криптографическими данными.
        entry_manager=entry_manager,
        key_manager=key_manager,
        authenticator=authenticator,
        state_manager=state_manager,
        clipboard_service=clipboard_service,
    )

    clipboard_service.set_notify_callback(window.show_toast)# устанавливаем коллбек для уведомлений сервиса буфера обмена, который будет вызывать метод show_toast главного окна для отображения уведомлений пользователю при изменении буфера обмена или других событиях, связанных с буфером обмена. это обеспечивает удобный способ информирования пользователя о действиях, связанных с буфером обмена, и позволяет отображать важные сообщения или предупреждения в контексте главного окна приложения.

    window._config = config# сохраняем ссылку на менеджер конфигурации в главном окне для доступа к настройкам приложения и возможности их изменения через интерфейс пользователя. это позволяет главному окну управлять настройками приложения, такими как путь к базе данных, параметры шифрования и предпочтения пользователя, и обеспечивает удобный способ настройки приложения без необходимости редактировать конфигурационные файлы вручную.

    window.show()
    sys.exit(app.exec())


if __name__ == "__main__":
    main()